#!/usr/bin/env node
// bashpass standalone bundle - generated by scripts/build-standalone.js
// DO NOT EDIT BY HAND

import { readFileSync, existsSync, mkdirSync, writeFileSync } from 'node:fs';
import { join, dirname } from 'node:path';
import { homedir } from 'node:os';

const BUILTIN_ALLOWLIST = ["ls","ls *","cat *","pwd","head","head *","tail *","wc *","which *","whoami","stat *","git status","git status *","git diff","git diff *","git log","git log *","git show","git show *","git branch","git branch *","git remote -v","grep *","awk *","sed -n *","node --version","npm --version","python --version","python3 --version","echo","echo *","env","uname *"];
const BUILTIN_DENYLIST = ["rm -rf /*","rm -rf /","rm -rf ~","rm -rf ~/*","rm -rf $HOME*","mkfs*","dd if=*","sudo *","su *","chmod 777 *","chmod -R 777 *","curl * | sh","curl * | bash","wget * | sh","wget * | bash","systemctl *","service *",":(){ :|:& };:","sh","bash"];

function matchPattern(pattern, text) {
  const regex = patternToRegex(pattern);
  return regex.test(text);
}

function patternToRegex(pattern) {
  const escaped = pattern.replace(/[.+?^${}()|[\]\\]/g, '\\$&');
  const regex = '^' + escaped.replace(/\*/g, '.*') + '$';
  return new RegExp(regex);
}

function classifySubcommand(subcmd, ruleSet) {
  for (const pattern of ruleSet.denyPatterns) {
    if (matchPattern(pattern, subcmd.rawText)) {
      return { decision: 'deny', matchedRule: pattern };
    }
  }
  for (const pattern of ruleSet.allowPatterns) {
    if (matchPattern(pattern, subcmd.rawText)) {
      return { decision: 'allow', matchedRule: pattern };
    }
  }
  return { decision: 'unknown', matchedRule: null };
}

function bashRuleToGlob(rule) {
  const m = /^Bash\((.+)\)$/.exec(rule);
  if (!m) return null;
  const inner = m[1];
  const colonIdx = inner.indexOf(':');
  if (colonIdx === -1) return inner;
  const cmd = inner.slice(0, colonIdx);
  const args = inner.slice(colonIdx + 1);
  return `${cmd} ${args}`;
}


class ParseError extends Error {
  constructor(message) {
    super(message);
    this.name = 'ParseError';
  }
}

const SEPARATORS = ['&&', '||', ';', '|', '&'];

function parseBashCommand(input) {
  return { subcommands: parseRecursive(input.trim()) };
}

function parseRecursive(input) {
  const innerCommands = [];
  const stripped = extractSubstitutions(input, innerCommands);
  const outerSegments = splitBySeparators(stripped)
    .map(seg => seg.trim())
    .filter(seg => seg.length > 0);
  const outerSubcommands = outerSegments
    .map(seg => {
      const tokens = seg.split(/\s+/).filter(Boolean);
      return {
        command: tokens[0] || '',
        args: tokens.slice(1),
        rawText: seg,
      };
    })
    .filter(s => s.command.length > 0);
  return [...outerSubcommands, ...innerCommands];
}

function extractSubstitutions(input, sink) {
  let result = '';
  let i = 0;
  let quote = null; // null | "'" | '"'
  while (i < input.length) {
    const ch = input[i];
    if (quote === "'") {
      if (ch === "'") quote = null;
      result += ch;
      i++;
      continue;
    }
    if (ch === '\\' && i + 1 < input.length) {
      result += ch + input[i + 1];
      i += 2;
      continue;
    }
    if (quote === '"') {
      if (ch === '"') { quote = null; result += ch; i++; continue; }
      // 双引号内仍展开 $() / 反引号
      if (input.startsWith('$(', i)) {
        const close = findMatching(input, i + 2, '(', ')');
        if (close === -1) throw new ParseError('Unclosed $(...) substitution');
        sink.push(...parseRecursive(input.slice(i + 2, close)));
        result += ' ';
        i = close + 1;
        continue;
      }
      if (ch === '`') {
        const close = input.indexOf('`', i + 1);
        if (close === -1) throw new ParseError('Unclosed backtick substitution');
        sink.push(...parseRecursive(input.slice(i + 1, close)));
        result += ' ';
        i = close + 1;
        continue;
      }
      result += ch;
      i++;
      continue;
    }
    // unquoted
    if (ch === "'" || ch === '"') { quote = ch; result += ch; i++; continue; }
    if (input.startsWith('$(', i)) {
      const close = findMatching(input, i + 2, '(', ')');
      if (close === -1) throw new ParseError('Unclosed $(...) substitution');
      sink.push(...parseRecursive(input.slice(i + 2, close)));
      result += ' ';
      i = close + 1;
      continue;
    }
    if (ch === '`') {
      const close = input.indexOf('`', i + 1);
      if (close === -1) throw new ParseError('Unclosed backtick substitution');
      sink.push(...parseRecursive(input.slice(i + 1, close)));
      result += ' ';
      i = close + 1;
      continue;
    }
    result += ch;
    i++;
  }
  if (quote !== null) throw new ParseError(`Unclosed ${quote === "'" ? 'single' : 'double'} quote`);
  return result;
}

function findMatching(input, start, open, close) {
  let depth = 1;
  for (let i = start; i < input.length; i++) {
    if (input[i] === open) depth++;
    else if (input[i] === close) {
      depth--;
      if (depth === 0) return i;
    }
  }
  return -1;
}

function splitBySeparators(input) {
  const result = [];
  let buffer = '';
  let i = 0;
  let quote = null;
  while (i < input.length) {
    const ch = input[i];
    if (quote) {
      if (ch === quote) quote = null;
      buffer += ch;
      i++;
      continue;
    }
    if (ch === '\\' && i + 1 < input.length) {
      buffer += ch + input[i + 1];
      i += 2;
      continue;
    }
    if (ch === "'" || ch === '"') { quote = ch; buffer += ch; i++; continue; }
    if (ch === '&') {
      const prev = i > 0 ? input[i - 1] : '';
      const next = i + 1 < input.length ? input[i + 1] : '';
      if (prev === '>' || prev === '<' || next === '>') {
        buffer += ch;
        i++;
        continue;
      }
    }
    let matched = false;
    for (const sep of SEPARATORS) {
      if (input.startsWith(sep, i)) {
        result.push(buffer);
        buffer = '';
        i += sep.length;
        matched = true;
        break;
      }
    }
    if (!matched) { buffer += ch; i++; }
  }
  if (buffer.length > 0) result.push(buffer);
  if (quote !== null) throw new ParseError(`Unclosed ${quote === "'" ? 'single' : 'double'} quote`);
  return result;
}






function loadUserAllowPatterns(options = {}) {
  const paths = options.paths || defaultSettingsPaths();
  const patterns = new Set();
  for (const p of paths) {
    try {
      const raw = readFileSync(p, 'utf8');
      const data = JSON.parse(raw);
      const allowList = data?.permissions?.allow;
      if (!Array.isArray(allowList)) continue;
      for (const rule of allowList) {
        const glob = bashRuleToGlob(rule);
        if (glob !== null) patterns.add(glob);
      }
    } catch {
      // 文件不存在或 JSON 无效 → 跳过，不抛错
    }
  }
  return [...patterns];
}

function defaultSettingsPaths() {
  return [
    join(process.cwd(), '.claude', 'settings.json'),
    join(homedir(), '.claude', 'settings.json'),
  ];
}





function defaultAckPath() {
  return join(homedir(), '.claude', '.bashpass-acknowledged');
}

function hasAcknowledged(path = defaultAckPath()) {
  return existsSync(path);
}

function ackNotice() {
  return [
    '',
    '⚠️  bashpass 首次启用提示 / First-time notice',
    '',
    'bashpass 会自动放行内置安全命令、自动拒绝内置危险命令。',
    '使用前请先阅读 DISCLAIMER.md 中的免责声明。',
    '',
    'bashpass automatically allows safe built-in commands and denies dangerous ones.',
    'Please read DISCLAIMER.md before use.',
    '',
    '接受方式 / To accept, run:',
    '  touch ~/.claude/.bashpass-acknowledged',
    '',
    '在此之前 bashpass 不会改变任何权限决策。',
    'Until then bashpass will not change any permission decisions.',
    '',
  ].join('\n');
}


function synthesizeDecision(classifications) {
  if (classifications.length === 0) return null;

  const denied = classifications.filter(c => c.decision === 'deny');
  if (denied.length > 0) {
    const reasons = denied.map(c => `"${c.subcmd.rawText}" 命中危险规则 ${c.matchedRule}`).join('；');
    return {
      permissionDecision: 'deny',
      permissionDecisionReason: `bashpass: ${reasons}`,
    };
  }

  const allAllow = classifications.every(c => c.decision === 'allow');
  if (allAllow) {
    const rules = [...new Set(classifications.map(c => c.matchedRule))].join(', ');
    return {
      permissionDecision: 'allow',
      permissionDecisionReason: `bashpass: 全部子命令命中安全规则 [${rules}]`,
    };
  }

  return null;
}


// === hook entry (inlined) ===








const READ_ONLY_TOOLS = new Set(['Read', 'Grep', 'Glob', 'WebFetch', 'WebSearch']);


function emit(decision) {
  if (decision === null) {
    process.stdout.write('{}\n');
    return;
  }
  process.stdout.write(JSON.stringify({
    hookSpecificOutput: {
      hookEventName: 'PreToolUse',
      ...decision,
    },
  }) + '\n');
}

function main() {
  if (!hasAcknowledged()) {
    process.stderr.write(ackNotice());
    emit(null);
    return;
  }

  let input;
  try {
    input = JSON.parse(readFileSync(0, 'utf8'));
  } catch {
    emit(null);
    return;
  }

  const toolName = input.tool_name;

  if (READ_ONLY_TOOLS.has(toolName)) {
    emit({
      permissionDecision: 'allow',
      permissionDecisionReason: `bashpass: ${toolName} 是只读工具，默认放行`,
    });
    return;
  }

  if (toolName !== 'Bash') {
    emit(null);
    return;
  }

  const command = input.tool_input?.command;
  if (typeof command !== 'string') {
    emit(null);
    return;
  }

  let parsed;
  try {
    parsed = parseBashCommand(command);
  } catch (e) {
    if (e instanceof ParseError) {
      emit(null);
      return;
    }
    throw e;
  }

  let allowPatterns, denyPatterns, userPatterns;
  try {
    allowPatterns = BUILTIN_ALLOWLIST;
    denyPatterns = BUILTIN_DENYLIST;
    userPatterns = loadUserAllowPatterns();
  } catch {
    emit(null);
    return;
  }

  const ruleSet = {
    allowPatterns: [...allowPatterns, ...userPatterns],
    denyPatterns,
  };

  const classifications = parsed.subcommands.map(subcmd => ({
    ...classifySubcommand(subcmd, ruleSet),
    subcmd,
  }));

  const decision = synthesizeDecision(classifications);
  debugLog(toolName, command, decision, classifications);
  emit(decision);
}

function debugLog(toolName, command, decision, classifications) {
  if (process.env.BASHPASS_DEBUG !== '1') return;
  const verdict = decision === null ? 'passthrough' : decision.permissionDecision;
  const rules = [...new Set(classifications.map(c => c.matchedRule).filter(Boolean))].join(',');
  const line = `[bashpass] decision=${verdict} tool=${toolName} subcmds=${classifications.length} rules=[${rules}] cmd="${command.replace(/"/g, '\\"')}"\n`;
  process.stderr.write(line);
}



main();
